#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int repeatedStringMatch(const char *A, const char *B) {
    int lenA = strlen(A);
    int lenB = strlen(B);
    int base = (lenB + lenA - 1) / lenA; // ceil
    int maxCopies = base + 1;
    int bufSize = lenA * maxCopies + 1;
    char *rep = (char *)malloc(bufSize);
    rep[0] = '\0';
    for (int i = 0; i < base; ++i) strcat(rep, A);
    if (strstr(rep, B) != NULL) {
        free(rep);
        return base;
    }
    strcat(rep, A); // one more copy
    if (strstr(rep, B) != NULL) {
        free(rep);
        return base + 1;
    }
    free(rep);
    return -1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char A[10005];
        char B[10005];
        scanf("%s", A);
        scanf("%s", B);
        printf("%d\n", repeatedStringMatch(A, B));
    }
    return 0;
}

