#include <bits/stdc++.h>
using namespace std;

int repeatedStringMatch(const string &A, const string &B) {
    int lenA = A.size();
    int lenB = B.size();
    int base = (lenB + lenA - 1) / lenA; // ceil
    string rep;
    rep.reserve(lenA * (base + 1));
    for (int i = 0; i < base; ++i) rep += A;
    if (rep.find(B) != string::npos) return base;
    rep += A;
    if (rep.find(B) != string::npos) return base + 1;
    return -1;
}

