import java.io.*;
import java.util.*;

public class Main {
    private static int repeatedStringMatch(String A, String B) {
        int lenA = A.length();
        int lenB = B.length();
        int base = (lenB + lenA - 1) / lenA; // ceil
        StringBuilder sb = new StringBuilder(lenA * (base + 1));
        for (int i = 0; i < base; i++) sb.append(A);
        if (sb.indexOf(B) != -1) return base;
        sb.append(A);
        if (sb.indexOf(B) != -1) return base + 1;
        return -1;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String A = br.readLine();
            String B = br.readLine();
            out.append(repeatedStringMatch(A, B)).append('\n');
        }
        System.out.print(out.toString());
    }
}

